    tags: [{ id: "tag-2", name: "links" }]
  });

  assert.deepEqual(
    {
      kind: note.kind,
      title: note.title,
      summary: note.summary,
      publishedAt: note.publishedAt,
      updatedAt: note.updatedAt,
      tags: note.tags,
      slug: note.slug,
      excerpt: note.excerpt
    },
    {
      kind: "note",
      title: "Published note",
      summary: "Note summary",
      publishedAt,
      updatedAt,
      tags: [{ id: "tag-1", name: "notes" }],
      slug: "published-note",
      excerpt: "Note excerpt"
    }
  );

  assert.deepEqual(
    {
      kind: link.kind,
