import { notFound } from "next/navigation";

import { ButtonLink, MetadataRow, Surface, TagChip, TagList } from "@/components/ui/primitives";
import { renderMarkdownToHtml } from "@/features/notes/markdown";
import { getPublishedNoteBySlug } from "@/features/notes/service";

type PublicNotePageProps = {
  params: Promise<{
    slug: string;
  }>;
};

export default async function PublicNotePage({ params }: PublicNotePageProps) {
  const { slug } = await params;
  const note = await getPublishedNoteBySlug(slug);

  if (!note) {
    notFound();
  }

  const publishedAt = note.publishedAt ?? note.updatedAt;
  const formattedPublishedAt = new Intl.DateTimeFormat("en", { dateStyle: "medium" }).format(publishedAt);

  return (
    <div className="feature-layout public-note-layout">
      <Surface as="article" className="public-note-card" tone="card">
        <div className="public-note-header">
          <div className="public-note-header-row">
            <MetadataRow leading className="public-note-meta">
              <span>Published note</span>
              <time dateTime={publishedAt.toISOString()}>{formattedPublishedAt}</time>
            </MetadataRow>
            <ButtonLink className="public-note-back-link" href="/" variant="ghost">
              Back to published notes
            </ButtonLink>
          </div>
          <div className="public-note-title-block">
            <p className="eyebrow">Public note</p>
            <h1>{note.title}</h1>
          </div>
        </div>
        <div
          className="markdown-preview public-note-body"
          data-testid="public-note-markdown"
          dangerouslySetInnerHTML={{ __html: renderMarkdownToHtml(note.markdown) }}
        />
        {(note.summary || note.tags.length > 0) && (
          <footer className="public-note-support" data-testid="public-note-support">
            {note.summary ? (
              <div className="public-note-support-block" data-testid="public-note-summary">
                <strong>AI summary</strong>
                <p className="note-generated-summary">{note.summary}</p>
              </div>
            ) : null}
            {note.tags.length > 0 ? (
              <div className="public-note-support-block" data-testid="public-note-tags">
                <strong>AI tags</strong>
                <TagList aria-label="Published note tags" className="public-note-tags">
                  {note.tags.map((tag) => (
                    <TagChip className="public-note-tag" key={tag.id}>
                      {tag.name}
                    </TagChip>
                  ))}
                </TagList>
              </div>
            ) : null}
          </footer>
        )}
      </Surface>
    </div>
  );
}

import "server-only";

import { requestEnrichment, retryEnrichment } from "@/features/enrichment/service";
import { notesRepo } from "@/features/notes/repo";
import { createNoteExcerpt } from "@/features/notes/markdown";
import type { NoteDraftInput } from "@/features/notes/types";
import { createUniqueNoteSlug } from "@/features/notes/slug";

function normalizeTitle(title: string) {
  const trimmedTitle = title.trim();

  return trimmedTitle || "Untitled note";
}

export async function listOwnerNotes(ownerId: string) {
  return notesRepo.listForOwner(ownerId);
}

export async function listPublishedNotes() {
  const notes = await notesRepo.listPublished();

  return notes.filter((note): note is typeof note & { publishedAt: Date } => note.publishedAt !== null);
}

export async function getOwnerNoteForEditor(ownerId: string, id: string) {
  return notesRepo.findByIdForOwner(ownerId, id);
}

export async function getPublishedNoteBySlug(slug: string) {
  const note = await notesRepo.findPublishedBySlug(slug);

  if (!note?.publishedAt) {
    return null;
  }

  return note;
}

export async function createDraftNote(ownerId: string, input: NoteDraftInput) {
  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  return notesRepo.create(ownerId, {
    title,
    slug: createUniqueNoteSlug(title, existingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title)
  });
}

export async function updateDraftNote(ownerId: string, id: string, input: NoteDraftInput) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  const siblingSlugs = existingSlugs.filter((slug) => slug !== existingNote.slug);
  return notesRepo.update(id, {
    title,
    slug: createUniqueNoteSlug(title, siblingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title)
  });
}

export async function publishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, true);
}

export async function unpublishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (!existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, false);
}

export async function retryNoteEnrichment(ownerId: string, id: string) {
  const note = await notesRepo.findByIdForOwner(ownerId, id);

  if (!note) {
    return null;
  }

  return retryEnrichment(notesRepo, id, note);
}

export async function startNoteEnrichment(id: string) {
  return requestEnrichment(notesRepo, id);
}

import "server-only";

import { Prisma } from "@prisma/client";

import { requestEnrichment, retryEnrichment } from "@/features/enrichment/service";
import { normalizeLinkInput } from "@/features/links/normalize";
import { linksRepo } from "@/features/links/repo";
import type { LinkDraftInput } from "@/features/links/types";

export class DuplicateLinkUrlError extends Error {
  constructor() {
    super("duplicate-link-url");
    this.name = "DuplicateLinkUrlError";
  }
}

export async function listOwnerLinks(ownerId: string) {
  return linksRepo.listForOwner(ownerId);
}

export async function listPublishedLinks() {
  const links = await linksRepo.listPublished();

  return links.filter((link): link is typeof link & { publishedAt: Date } => link.publishedAt !== null);
}

export async function createSavedLink(ownerId: string, input: LinkDraftInput) {
  const normalizedInput = normalizeLinkInput(input);

  try {
    return await linksRepo.create(ownerId, normalizedInput);
  } catch (error) {
    if (error instanceof Prisma.PrismaClientKnownRequestError && error.code === "P2002") {
      throw new DuplicateLinkUrlError();
    }

    throw error;
  }
}

export async function publishLink(ownerId: string, id: string) {
  const existingLink = await linksRepo.findByIdForOwner(ownerId, id);

  if (!existingLink) {
    return null;
  }

  if (existingLink.isPublished) {
    return existingLink;
  }

  return linksRepo.updatePublication(id, true);
}

export async function unpublishLink(ownerId: string, id: string) {
  const existingLink = await linksRepo.findByIdForOwner(ownerId, id);

  if (!existingLink) {
    return null;
  }

  if (!existingLink.isPublished) {
    return existingLink;
  }

  return linksRepo.updatePublication(id, false);
}

export async function retryLinkEnrichment(ownerId: string, id: string) {
  const link = await linksRepo.findByIdForOwner(ownerId, id);

  if (!link) {
